#ifdef cl_khr_fp64
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

typedef float fp;

__kernel void extract_kernel(long d_Ne,
                             __global fp *d_I)
{
    size_t ei = get_global_id(0);
    if ((long)ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / (fp)255.0f);
    }
}

__kernel void prepare_kernel(long d_Ne,
                             __global fp *d_I,
                             __global fp *d_sums,
                             __global fp *d_sums2)
{
    size_t ei = get_global_id(0);
    if ((long)ei < d_Ne) {
        fp v = d_I[ei];
        d_sums[ei] = v;
        d_sums2[ei] = v * v;
    }
}

__kernel void reduce_kernel(long d_Ne,
                            long d_no,
                            int d_mul,
                            __global fp *d_sums,
                            __global fp *d_sums2,
                            int blocks2_work_size)
{
    (void)d_Ne;
    (void)blocks2_work_size;

    const int bx = (int)get_group_id(0);
    const int tx = (int)get_local_id(0);
    const int L  = (int)get_local_size(0);
    const int gridx = (int)get_num_groups(0);
    const long ei = (long)bx * (long)L + (long)tx;

    __local fp d_psum[1024];
    __local fp d_psum2[1024];

    int nf = L - (gridx * L - (int)d_no);
    int df = 0;

    if (ei < d_no) {
        d_psum[tx] = d_sums[ei * (long)d_mul];
        d_psum2[tx] = d_sums2[ei * (long)d_mul];
    } else {
        d_psum[tx] = 0.0f;
        d_psum2[tx] = 0.0f;
    }

    if (nf == L) {
        for (int i = 2; i <= L; i = 2 * i) {
            if (((tx + 1) % i) == 0) {
                d_psum[tx] += d_psum[tx - i / 2];
                d_psum2[tx] += d_psum2[tx - i / 2];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }

        if (tx == (L - 1)) {
            d_sums[(long)bx * (long)d_mul * (long)L] = d_psum[tx];
            d_sums2[(long)bx * (long)d_mul * (long)L] = d_psum2[tx];
        }
    } else {
        if (bx != (gridx - 1)) {
            for (int i = 2; i <= L; i = 2 * i) {
                if (((tx + 1) % i) == 0) {
                    d_psum[tx] += d_psum[tx - i / 2];
                    d_psum2[tx] += d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (L - 1)) {
                d_sums[(long)bx * (long)d_mul * (long)L] = d_psum[tx];
                d_sums2[(long)bx * (long)d_mul * (long)L] = d_psum2[tx];
            }
        } else {
            for (int i = 2; i <= L; i = 2 * i) {
                if (nf >= i) {
                    df = i;
                }
            }

            for (int i = 2; i <= df; i = 2 * i) {
                if (((tx + 1) % i) == 0 && tx < df) {
                    d_psum[tx] += d_psum[tx - i / 2];
                    d_psum2[tx] += d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (df - 1)) {
                for (int i = bx * L + df; i < bx * L + nf; i++) {
                    d_psum[tx] += d_sums[i];
                    d_psum2[tx] += d_sums2[i];
                }
                d_sums[(long)bx * (long)d_mul * (long)L] = d_psum[tx];
                d_sums2[(long)bx * (long)d_mul * (long)L] = d_psum2[tx];
            }
        }
    }
}

__kernel void srad_kernel(fp lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          __global int *iN,
                          __global int *iS,
                          __global int *jE,
                          __global int *jW,
                          __global fp *d_dN,
                          __global fp *d_dS,
                          __global fp *d_dW,
                          __global fp *d_dE,
                          fp q0sqr,
                          __global fp *d_c,
                          __global fp *d_I)
{
    (void)lambda;
    (void)Nr;

    size_t ei = get_global_id(0);
    if ((long)ei < Ne) {
        int row = (int)(ei / (size_t)Nc);
        int col = (int)(ei % (size_t)Nc);

        fp Jc = d_I[ei];

        fp dN = d_I[(size_t)iN[row] * (size_t)Nc + (size_t)col] - Jc;
        fp dS = d_I[(size_t)iS[row] * (size_t)Nc + (size_t)col] - Jc;
        fp dW = d_I[(size_t)row * (size_t)Nc + (size_t)jW[col]] - Jc;
        fp dE = d_I[(size_t)row * (size_t)Nc + (size_t)jE[col]] - Jc;

        d_dN[ei] = dN;
        d_dS[ei] = dS;
        d_dW[ei] = dW;
        d_dE[ei] = dE;

        fp G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
        fp L = (dN + dS + dW + dE) / Jc;

        fp num = (fp)0.5f * G2 - (fp)(1.0f / 16.0f) * (L * L);
        fp den = (fp)1.0f + (fp)0.25f * L;
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * ((fp)1.0f + q0sqr));
        fp c = (fp)1.0f / ((fp)1.0f + den);

        if (c < (fp)0.0f) c = (fp)0.0f;
        else if (c > (fp)1.0f) c = (fp)1.0f;

        d_c[ei] = c;
    }
}

__kernel void srad2_kernel(fp lambda,
                           int Nr,
                           int Nc,
                           long Ne,
                           __global int *iN,
                           __global int *iS,
                           __global int *jE,
                           __global int *jW,
                           __global fp *d_dN,
                           __global fp *d_dS,
                           __global fp *d_dW,
                           __global fp *d_dE,
                           __global fp *d_c,
                           __global fp *d_I)
{
    (void)Nr;
    (void)iN;
    (void)jW;

    size_t ei = get_global_id(0);
    if ((long)ei < Ne) {
        int row = (int)(ei / (size_t)Nc);
        int col = (int)(ei % (size_t)Nc);

        fp cN = d_c[ei];
        fp cS = d_c[(size_t)iS[row] * (size_t)Nc + (size_t)col];
        fp cW = d_c[ei];
        fp cE = d_c[(size_t)row * (size_t)Nc + (size_t)jE[col]];

        fp D = cN * d_dN[ei] + cS * d_dS[ei] + cW * d_dW[ei] + cE * d_dE[ei];
        d_I[ei] = d_I[ei] + (fp)0.25f * lambda * D;
    }
}

__kernel void compress_kernel(long d_Ne,
                              __global fp *d_I)
{
    size_t ei = get_global_id(0);
    if ((long)ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * (fp)255.0f;
    }
}
